mapper.select:
SELECT smr.id AS id, smr.school_year AS schoolYear, grade.id AS classGroupId, grade.grade_group_name AS classGroupName, cla.id AS classId, cla.class_name AS className, smr.student_id AS studentId, smr.student_name AS studentName, stu.gender AS gender, sma.allergy AS allergy, sma.serious_chronic_disease AS seriousChronicDisease, sma.medical_notes AS medicalNotes, sh.name AS hospital, smr.chief_complaint AS chiefComplaint, smr.treatment AS treatment, smr.notes AS notes, smr.consultation_date AS consultationDate, smr.temperature AS temperature, smr.fever AS fever, smr.cough AS cough, smr.runny_nose AS runny_nose, smr.sore_throat AS sore_throat, smr.dizziness AS dizziness, smr.headache AS headache, smr.nosebleed AS nosebleed, smr.nausea AS nausea, smr.vomiting_count AS vomitingCount, smr.abdominal_pain AS abdominalPain, smr.diarrhea_count AS diarrheaCount FROM student_medical_record smr LEFT JOIN student_medical_attention sma on sma.student_id = smr.student_id LEFT JOIN student_info stu ON stu.id = smr.student_id LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN sys_hospital sh ON sh.id = stu.emergency_hospital WHERE smr.deleted = 0
AND smr.school_id = #{reqModel.schoolId}
AND smr.school_year = #{reqModel.schoolYear}
AND smr.class_id = #{reqModel.classId}
AND smr.student_id = #{reqModel.studentId}
AND smr.consultation_date >= #{reqModel.startDate}
AND smr.consultation_date <= #{reqModel.endDate}
ORDER BY smr.create_time desc
